/**
 * PR Comment Builder
 * Builds and posts a comprehensive comment marking the PR with test results
 * 
 * This is STEP 6: Mark the PR
 */

/**
 * Build comprehensive PR comment
 * @param {Object} results - All test results and analysis
 * @returns {string} Markdown comment
 */
async function buildComment(results) {
  const {
    impactScore,
    testsToRun,
    testsToSkip,
    frontendResults,
    backendResults,
    e2eResults,
    failuresFound,
    jiraIssue,
  } = results;

  const frontend = parseResults(frontendResults);
  const backend = parseResults(backendResults);
  const e2e = parseResults(e2eResults);

  const overallPassed =
    frontend.passed && backend.passed && e2e.passed && !failuresFound;

  const statusEmoji = overallPassed ? '✅' : '❌';
  const statusText = overallPassed ? 'All Tests Passed' : 'Tests Failed';

  const comment = `
## ${statusEmoji} ${statusText}

### 🤖 AI Analysis
- **Impact Score**: ${impactScore}/100 ${getRiskBadge(impactScore)}
- **Tests Selected**: ${Array.isArray(testsToRun) ? testsToRun.join(', ') : 'all'}
- **Tests Skipped**: ${Array.isArray(testsToSkip) && testsToSkip.length > 0 ? testsToSkip.join(', ') : 'none'}

### 📊 Test Results

#### 🧪 Frontend Tests
${buildTestBlock(frontend)}

#### 🧪 Backend Tests
${buildTestBlock(backend)}

#### 🎭 E2E Tests
${buildTestBlock(e2e)}

### 📈 Summary
| Category | Result |
|----------|--------|
| Total Tests | ${frontend.total + backend.total + e2e.total} |
| Passed | ${frontend.passed + backend.passed + e2e.passed} ✅ |
| Failed | ${frontend.failed + backend.failed + e2e.failed} ${frontend.failed + backend.failed + e2e.failed > 0 ? '❌' : '✅'} |
| Pass Rate | ${calculatePassRate(frontend, backend, e2e)}% |

${
  failuresFound
    ? `
### 🐛 Failures Detected
**JIRA Issue**: [${jiraIssue}](${getJiraUrl(jiraIssue)})

The AI has automatically analyzed failures and created a JIRA issue for tracking.
`
    : `
### ✨ Quality Score
**Excellent!** All tests passed. Keep up the good work! 🚀
`
}

### 💡 Next Steps
${getNextSteps(overallPassed, impactScore)}

---
*Generated by 🤖 AI Smart Testing Pipeline*
`;

  return comment;
}

/**
 * Parse test results object
 */
function parseResults(results) {
  if (!results) {
    return {
      passed: 0,
      failed: 0,
      total: 0,
      passed: true,
    };
  }

  const passed = parseInt(results.passed) || 0;
  const failed = parseInt(results.failed) || 0;
  const total = parseInt(results.total) || 0;

  return {
    passed,
    failed,
    total,
    passed: failed === 0,
  };
}

/**
 * Build test result block
 */
function buildTestBlock(results) {
  if (results.total === 0) {
    return '⏭️ Not run (not affected by changes)';
  }

  const percentage = results.total > 0 ? Math.round((results.passed / results.total) * 100) : 0;
  const icon = results.passed ? '✅' : '❌';

  return `${icon} ${results.passed}/${results.total} passed (${percentage}%)`;
}

/**
 * Calculate overall pass rate
 */
function calculatePassRate(frontend, backend, e2e) {
  const total = frontend.total + backend.total + e2e.total;
  const passed = frontend.passed + backend.passed + e2e.passed;

  if (total === 0) return '100';
  return Math.round((passed / total) * 100);
}

/**
 * Get risk badge based on impact score
 */
function getRiskBadge(score) {
  const scoreNum = parseInt(score) || 0;
  if (scoreNum >= 70) return '🔴 High Risk';
  if (scoreNum >= 40) return '🟡 Medium Risk';
  return '🟢 Low Risk';
}

/**
 * Get next steps based on results
 */
function getNextSteps(allPassed, impactScore) {
  const scoreNum = parseInt(impactScore) || 0;

  if (allPassed) {
    if (scoreNum >= 70) {
      return `
- ✅ High-impact changes with passing tests - excellent!
- 🔍 Consider manual QA for critical features
- 📝 Add regression tests for edge cases
- 🚀 Ready to merge after code review
`;
    }
    return `
- ✅ All tests passing - looks good!
- 📝 Consider adding tests for new features
- 🚀 Ready to merge
`;
  }

  return `
- ❌ Tests are failing - review JIRA issue above
- 🔧 Fix the issues and push new commits
- 🤖 AI will automatically re-analyze and update this comment
- 📞 If stuck, ask for help in comments
`;
}

/**
 * Get JIRA URL
 */
function getJiraUrl(issueKey) {
  if (!issueKey || issueKey === 'None') {
    return '#';
  }
  // Extract host from env if available, otherwise use placeholder
  const jiraHost = process.env.JIRA_HOST || 'https://your-jira.atlassian.net';
  return `${jiraHost}/browse/${issueKey}`;
}

module.exports = { buildComment };
